mapper.select:
select
	t1.id                             ,
	t1.secret_level                   ,
	t1.project_id                     ,
	t1.publish_no                     ,
	t1.publish_code                   ,
	t1.publish_date                   ,
	t1.payment_type                   ,
	t1.payment_year                   ,
	t1.payment_month                  ,
	t1.budget_fund                    ,
	t1.budget_special_fund            ,
	t1.bank_loans                     ,
	t1.self_fund                      ,
	t1.status                         ,
	t1.remark                         ,
	t1.attribute_01                   ,
	t1.attribute_02                   ,
	t1.attribute_03                   ,
	t1.attribute_04                   ,
	t1.attribute_05                   ,
	t1.created_by                     ,
	t1.last_updated_by                ,
	t1.last_update_date               ,
	t1.creation_date                  ,
	t1.last_update_ip                 ,
	t1.version                        ,
	t1.created_dept                   ,
	t1.org_identity                   
from jg_payment_plan 	t1


			and t1.ID =#{id}


			and t1.SECRET_LEVEL =#{secretLevel}


			and t1.PROJECT_ID =#{projectId}


			and t1.PUBLISH_NO =#{publishNo}


			and t1.PUBLISH_CODE =#{publishCode}


			and t1.PUBLISH_DATE >= #{publishDateBegin}


			and t1.PUBLISH_DATE <= #{publishDateEnd}


			and t1.PAYMENT_TYPE =#{paymentType}


			and t1.PAYMENT_YEAR =#{paymentYear}


			and t1.PAYMENT_MONTH =#{paymentMonth}


			and t1.BUDGET_FUND =#{budgetFund}


			and t1.BUDGET_SPECIAL_FUND =#{budgetSpecialFund}


			and t1.BANK_LOANS =#{bankLoans}


			and t1.SELF_FUND =#{selfFund}


			and t1.STATUS =#{status}


			and t1.REMARK =#{remark}


			and t1.ATTRIBUTE_01 =#{attribute01}


			and t1.ATTRIBUTE_02 =#{attribute02}


			and t1.ATTRIBUTE_03 =#{attribute03}


			and t1.ATTRIBUTE_04 =#{attribute04}


			and t1.ATTRIBUTE_05 =#{attribute05}


			and t1.CREATED_BY =#{createdBy}


			and t1.LAST_UPDATED_BY =#{lastUpdatedBy}


			and t1.LAST_UPDATE_DATE =#{lastUpdateDate}


			and t1.CREATION_DATE =#{creationDate}


			and t1.LAST_UPDATE_IP =#{lastUpdateIp}


			and t1.VERSION =#{version}


			and t1.CREATED_DEPT =#{createdDept}


			and t1.ORG_IDENTITY =#{orgIdentity}
